import {
	InvalidSourceError,
	RemoteFetchError,
	RemoteFetchTimeoutError,
	RemoteFetchTooLargeError,
	RequestAbortedError,
	UnsupportedRuntimeError,
} from "../errors";

const LABEL_SUFFIX_REGEX = /(\.[^.]+)+$/;
const REDIRECT_STATUSES = new Set([301, 302, 303, 307, 308]);
const DEFAULT_MAX_SOURCE_BYTES = 1024 * 1024 * 1024 * 5;

type UploadLike = Blob | ArrayBuffer | Uint8Array | ReadableStream<Uint8Array>;

type UploadSource =
	| { file: UploadLike; label?: string }
	| { url: string; label?: string }
	| { path: string; label?: string };

type MaterializedSource = {
	file: Blob;
	label: string;
};

async function materializeSource(
	source: UploadSource,
	opts: {
		fetchImpl: typeof fetch;
		timeoutMs: number;
		maxSourceBytes: number;
		signal?: AbortSignal;
	},
): Promise<MaterializedSource> {
	if ("file" in source) {
		return {
			file: await toBlob(source.file, opts.maxSourceBytes),
			label: source.label ?? "Uploaded file",
		};
	}

	if ("path" in source) {
		const file = await readPathSource(source.path, opts.maxSourceBytes);
		return {
			file: new Blob([toArrayBuffer(file.bytes)]),
			label: source.label ?? labelFromPath(source.path),
		};
	}

	const url = parseSourceUrl(source.url);
	const remote = await downloadUrlSource(url, opts);
	return {
		file: remote.file,
		label: source.label ?? labelFromUrl(remote.url),
	};
}

function labelFromPath(value: string): string {
	const raw = value.replace(/\\/g, "/").split("/").at(-1)?.trim() ?? "";
	if (!raw) return "Uploaded file";
	const label = raw.replace(LABEL_SUFFIX_REGEX, "").trim();
	if (label) return label;
	return "Uploaded file";
}

function labelFromUrl(url: URL): string {
	const raw = url.pathname.split("/").at(-1)?.trim() ?? "";
	if (!raw) return "Uploaded file";
	const label = decodeURIComponent(raw).replace(LABEL_SUFFIX_REGEX, "").trim();
	if (label) return label;
	return "Uploaded file";
}

function parseSourceUrl(value: string): URL {
	if (!value.trim()) {
		throw new InvalidSourceError("source.url must be a non-empty string", {
			code: "invalid_source",
		});
	}

	let url: URL;
	try {
		url = new URL(value);
	} catch {
		throw new InvalidSourceError("source.url must be a valid URL", {
			code: "invalid_source",
		});
	}

	if (url.protocol !== "http:" && url.protocol !== "https:") {
		throw new InvalidSourceError("source.url must use http: or https:", {
			code: "invalid_source",
		});
	}

	return url;
}

async function readPathSource(
	value: string,
	maxSourceBytes: number,
): Promise<{ bytes: Uint8Array; path: string }> {
	if (!value.trim()) {
		throw new InvalidSourceError("source.path must be a non-empty string", {
			code: "invalid_source",
		});
	}

	let fs: typeof import("node:fs/promises");
	let p: typeof import("node:path");
	try {
		fs = await import("node:fs/promises");
		p = await import("node:path");
	} catch (cause) {
		throw new UnsupportedRuntimeError(
			"source.path is not supported in this runtime",
			{ cause, code: "unsupported_runtime" },
		);
	}

	const path = p.resolve(value);
	const stat = await fs.stat(path).catch((cause) => {
		throw new InvalidSourceError(`source.path could not be read: ${path}`, {
			cause,
			code: "invalid_source",
		});
	});
	if (stat.isDirectory()) {
		throw new InvalidSourceError("source.path must point to a file", {
			code: "invalid_source",
		});
	}
	assertWithinLimit(stat.size, maxSourceBytes, {
		kind: "source.path",
		url: path,
	});

	return { bytes: await fs.readFile(path), path };
}

async function downloadUrlSource(
	start: URL,
	opts: {
		fetchImpl: typeof fetch;
		timeoutMs: number;
		maxSourceBytes: number;
		signal?: AbortSignal;
	},
): Promise<{ file: Blob; url: URL }> {
	let url = start;

	for (let i = 0; i <= 5; i++) {
		// biome-ignore lint/performance/noAwaitInLoops: redirect resolution is sequential by protocol
		const response = await fetchWithTimeout(url, opts);
		const redirected = readRedirect(response, url, i);
		if (redirected) {
			url = redirected;
			continue;
		}
		if (!response.ok) {
			throw new RemoteFetchError(
				`Failed to download source.url (status ${response.status})`,
				{
					code: "remote_fetch_failed",
					status: response.status,
					url: url.toString(),
				},
			);
		}

		const size = parseContentLength(response.headers.get("content-length"));
		if (size !== undefined) {
			assertWithinLimit(size, opts.maxSourceBytes, {
				kind: "source.url",
				status: response.status,
				url: url.toString(),
			});
		}

		const body = new Uint8Array(await response.arrayBuffer());
		assertWithinLimit(body.byteLength, opts.maxSourceBytes, {
			kind: "source.url",
			status: response.status,
			url: url.toString(),
		});

		return {
			file: new Blob([toArrayBuffer(body)], {
				type: response.headers.get("content-type") ?? undefined,
			}),
			url,
		};
	}

	throw new RemoteFetchError("Failed to download source.url", {
		code: "remote_fetch_failed",
		url: start.toString(),
	});
}

function readRedirect(response: Response, url: URL, hops: number): URL | null {
	if (!REDIRECT_STATUSES.has(response.status)) return null;
	if (hops === 5) {
		throw new RemoteFetchError("source.url exceeded the redirect limit", {
			code: "remote_fetch_redirect_limit",
			status: response.status,
			url: url.toString(),
		});
	}
	const next = response.headers.get("location");
	if (!next) {
		throw new RemoteFetchError(
			"source.url returned a redirect without a location header",
			{
				code: "remote_fetch_failed",
				status: response.status,
				url: url.toString(),
			},
		);
	}
	return new URL(next, url);
}

async function fetchWithTimeout(
	url: URL,
	opts: {
		fetchImpl: typeof fetch;
		timeoutMs: number;
		signal?: AbortSignal;
	},
): Promise<Response> {
	const ctrl = new AbortController();
	const timeout = setTimeout(() => {
		ctrl.abort(
			new RemoteFetchTimeoutError("source.url timed out while downloading", {
				code: "remote_fetch_timeout",
				url: url.toString(),
			}),
		);
	}, opts.timeoutMs);

	if (opts.signal?.aborted) {
		clearTimeout(timeout);
		throw new RequestAbortedError("source.url download was aborted", {
			code: "request_aborted",
		});
	}

	opts.signal?.addEventListener(
		"abort",
		() =>
			ctrl.abort(
				new RequestAbortedError("source.url download was aborted", {
					code: "request_aborted",
				}),
			),
		{ once: true },
	);

	try {
		return await opts.fetchImpl(url.toString(), {
			method: "GET",
			redirect: "manual",
			signal: ctrl.signal,
		});
	} catch (cause) {
		if (ctrl.signal.aborted && ctrl.signal.reason instanceof Error) {
			throw ctrl.signal.reason;
		}
		throw new RemoteFetchError("Failed to download source.url", {
			cause,
			code: "remote_fetch_failed",
			url: url.toString(),
		});
	} finally {
		clearTimeout(timeout);
	}
}

async function toBlob(file: UploadLike, maxSourceBytes: number): Promise<Blob> {
	if (typeof Blob !== "undefined" && file instanceof Blob) {
		assertWithinLimit(file.size, maxSourceBytes, { kind: "source.file" });
		return file;
	}

	if (file instanceof ArrayBuffer) {
		assertWithinLimit(file.byteLength, maxSourceBytes, { kind: "source.file" });
		return new Blob([file]);
	}

	if (file instanceof Uint8Array) {
		assertWithinLimit(file.byteLength, maxSourceBytes, { kind: "source.file" });
		return new Blob([toArrayBuffer(file)]);
	}

	if (typeof ReadableStream !== "undefined" && file instanceof ReadableStream) {
		if (typeof Response === "undefined") {
			throw new UnsupportedRuntimeError(
				"ReadableStream upload requires Response to convert stream to Blob",
				{ code: "unsupported_runtime" },
			);
		}
		const blob = await new Response(file).blob();
		assertWithinLimit(blob.size, maxSourceBytes, { kind: "source.file" });
		return blob;
	}

	throw new InvalidSourceError("Unsupported file type for upload()", {
		code: "invalid_source",
	});
}

function assertWithinLimit(
	size: number,
	maxSourceBytes: number,
	opts: { kind: string; url?: string; status?: number },
): void {
	if (size <= maxSourceBytes) return;
	throw new RemoteFetchTooLargeError(
		`${opts.kind} exceeds the supported upload limit of ${maxSourceBytes} bytes`,
		{
			code: "source_too_large",
			status: opts.status,
			url: opts.url,
		},
	);
}

function parseContentLength(value: string | null): number | undefined {
	if (!value) return;
	const size = Number(value);
	if (!Number.isFinite(size) || size < 0) return;
	return size;
}

function toArrayBuffer(bytes: Uint8Array): ArrayBuffer {
	return bytes.buffer.slice(
		bytes.byteOffset,
		bytes.byteOffset + bytes.byteLength,
	) as ArrayBuffer;
}

export type { MaterializedSource, UploadLike, UploadSource };
export {
	DEFAULT_MAX_SOURCE_BYTES,
	labelFromPath,
	labelFromUrl,
	materializeSource,
	parseSourceUrl,
	readPathSource,
};
