import { jobResponse, jobStreamEvent } from "@mappa-ai/contracts/v1/jobs";
import {
	ConduitError,
	JobCanceledError,
	JobFailedError,
	StreamError,
	TimeoutError,
} from "../errors";
import type { Job, JobEvent, WaitOptions } from "../types";
import { withDeadline } from "../utils";
import type { SSEEvent, Transport } from "./transport";
import { parseRes } from "./validate";

class JobsResource {
	private readonly transport: Transport;

	constructor(transport: Transport) {
		this.transport = transport;
	}

	async get(
		jobId: string,
		opts?: { requestId?: string; signal?: AbortSignal },
	): Promise<Job> {
		const res = await this.transport.request<Job>({
			method: "GET",
			path: `/v1/jobs/${encodeURIComponent(jobId)}`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return parseRes(jobResponse, res.data, "jobs.get");
	}

	async cancel(
		jobId: string,
		opts?: {
			idempotencyKey?: string;
			requestId?: string;
			signal?: AbortSignal;
		},
	): Promise<Job> {
		const res = await this.transport.request<Job>({
			idempotencyKey: opts?.idempotencyKey,
			method: "POST",
			path: `/v1/jobs/${encodeURIComponent(jobId)}/cancel`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return parseRes(jobResponse, res.data, "jobs.cancel");
	}

	async wait(jobId: string, opts?: WaitOptions): Promise<Job> {
		const timeoutMs = opts?.timeoutMs ?? 300000;
		const deadline = withDeadline(timeoutMs, {
			onTimeout: () =>
				new TimeoutError(
					`Timed out waiting for job ${jobId} after ${timeoutMs}ms`,
					{
						code: "timeout",
					},
				),
			signal: opts?.signal,
		});

		try {
			for await (const event of this.stream(jobId, {
				onEvent: opts?.onEvent,
				signal: deadline.signal,
			})) {
				if (event.type !== "terminal") continue;
				const job = event.job;
				if (job.status === "succeeded") return job;
				if (job.status === "failed") {
					throw new JobFailedError(jobId, job.error?.message ?? "Job failed", {
						cause: job.error,
						code: job.error?.code,
						requestId: job.requestId,
					});
				}
				if (job.status === "canceled") {
					throw new JobCanceledError(jobId, "Job canceled", {
						cause: job.error,
						requestId: job.requestId,
					});
				}
			}

			throw new TimeoutError(
				`Timed out waiting for job ${jobId} after ${timeoutMs}ms`,
				{
					code: "timeout",
				},
			);
		} finally {
			deadline.cleanup();
		}
	}

	async *stream(
		jobId: string,
		opts?: { signal?: AbortSignal; onEvent?: (e: JobEvent) => void },
	): AsyncIterable<JobEvent> {
		yield* this.streamWithRetry(jobId, opts);
	}

	private async *streamWithRetry(
		jobId: string,
		opts?: { signal?: AbortSignal; onEvent?: (e: JobEvent) => void },
	): AsyncGenerator<JobEvent> {
		const maxRetries = 3;
		let state: { lastEventId?: string; retries: number } = { retries: 0 };

		while (state.retries < maxRetries) {
			state = yield* this.runStreamAttempt(jobId, opts, state, maxRetries);
			if (state.retries < 0) {
				return;
			}
		}

		throw new StreamError(
			`Failed to get status for job ${jobId} after ${maxRetries} retries`,
			{
				jobId,
				lastEventId: state.lastEventId,
				retryCount: maxRetries,
			},
		);
	}

	private async *runStreamAttempt(
		jobId: string,
		opts: { signal?: AbortSignal; onEvent?: (e: JobEvent) => void } | undefined,
		state: { lastEventId?: string; retries: number },
		maxRetries: number,
	): AsyncGenerator<JobEvent, { lastEventId?: string; retries: number }> {
		try {
			const terminal = yield* this.streamAttempt(jobId, opts, state);
			if (terminal) {
				return { ...state, retries: -1 };
			}
			const retries = state.retries + 1;
			if (retries < maxRetries) {
				await this.backoff(retries);
			}
			return { ...state, retries };
		} catch (err) {
			if (opts?.signal?.aborted) throw err;
			const retries = state.retries + 1;
			if (retries >= maxRetries) {
				throw new StreamError(
					`Stream connection failed for job ${jobId} after ${maxRetries} retries`,
					{
						cause: err,
						jobId,
						lastEventId: state.lastEventId,
						retryCount: retries,
					},
				);
			}
			await this.backoff(retries);
			return { ...state, retries };
		}
	}

	private async *streamAttempt(
		jobId: string,
		opts: { signal?: AbortSignal; onEvent?: (e: JobEvent) => void } | undefined,
		state: { lastEventId?: string; retries: number },
	): AsyncGenerator<JobEvent, boolean> {
		const stream = this.transport.streamSSE<unknown>(
			`/v1/jobs/${encodeURIComponent(jobId)}/stream`,
			{ lastEventId: state.lastEventId, signal: opts?.signal },
		);
		for await (const sse of stream) {
			state.lastEventId = sse.id;
			const handled = this.handleSseEvent(sse);
			if (!handled.event) {
				if (handled.terminal) return true;
				continue;
			}
			state.retries = 0;
			opts?.onEvent?.(handled.event);
			yield handled.event;
			if (handled.terminal) return true;
		}
		return false;
	}

	private handleSseEvent(sse: SSEEvent<unknown>): {
		event?: JobEvent;
		terminal: boolean;
	} {
		if (sse.event === "error") {
			const err = readSseError(sse.data);
			throw new ConduitError(err.message ?? "Unknown SSE error", {
				code: err.code,
			});
		}
		if (sse.event === "heartbeat") {
			return { terminal: false };
		}
		const event = this.mapSSEToJobEvent(sse);
		if (!event) {
			return { terminal: sse.event === "terminal" };
		}
		return { event, terminal: sse.event === "terminal" };
	}

	private mapSSEToJobEvent(sse: SSEEvent<unknown>): JobEvent | null {
		const parsed = parseRes(
			jobStreamEvent,
			{
				data: sse.data,
				event: sse.event,
				id: sse.id ?? "",
			},
			"jobs.stream event",
		);
		if (parsed.event === "status")
			return { job: parsed.data.job, type: "status" };
		if (parsed.event === "stage") {
			return {
				job: parsed.data.job,
				progress: parsed.data.progress,
				stage: parsed.data.stage,
				type: "stage",
			};
		}
		if (parsed.event === "terminal")
			return { job: parsed.data.job, type: "terminal" };
		return null;
	}

	private async backoff(attempt: number): Promise<void> {
		const base = Math.min(1000 * 2 ** attempt, 10000);
		const offset = base * 0.5 * Math.random();
		await new Promise((r) => setTimeout(r, base + offset));
	}
}

function readSseError(data: unknown): { code?: string; message?: string } {
	if (!data || typeof data !== "object") return {};
	const err = data as Record<string, unknown>;
	return {
		code: typeof err.code === "string" ? err.code : undefined,
		message: typeof err.message === "string" ? err.message : undefined,
	};
}

export { JobsResource };
