import { ConduitError } from "../errors";

type ParseResult<T> =
	| { success: true; data: T }
	| { success: false; error: unknown };

type Schema<T> = {
	safeParse: (input: unknown) => ParseResult<T>;
};

function summarize(err: unknown): string {
	if (!err || typeof err !== "object") return "unknown validation error";
	if (!("issues" in err && Array.isArray(err.issues))) {
		return "unknown validation error";
	}
	const items = err.issues
		.slice(0, 3)
		.map((issue) => {
			if (!issue || typeof issue !== "object") return "invalid value";
			const path =
				"path" in issue && Array.isArray(issue.path) && issue.path.length > 0
					? issue.path.join(".")
					: "root";
			const msg =
				"message" in issue && typeof issue.message === "string"
					? issue.message
					: "invalid value";
			return `${path}: ${msg}`;
		})
		.join("; ");
	return items || "unknown validation error";
}

export function parseReq<T>(
	schema: Schema<T>,
	input: unknown,
	name: string,
): T {
	const out = schema.safeParse(input);
	if (out.success) return out.data;
	throw new ConduitError(`Invalid ${name}: ${summarize(out.error)}`, {
		cause: out.error,
		code: "invalid_request",
	});
}

export function parseRes<T>(
	schema: Schema<T>,
	input: unknown,
	name: string,
): T {
	const out = schema.safeParse(input);
	if (out.success) return out.data;
	throw new ConduitError(`Invalid ${name} response: ${summarize(out.error)}`, {
		cause: out.error,
		code: "invalid_response",
	});
}
