import { InitializationError } from "./errors";
import { EntitiesResource } from "./resources/entities";
import { FilesResource } from "./resources/files";
import { JobsResource } from "./resources/jobs";
import { MatchingAnalysisResource } from "./resources/matching-analysis";
import { ReportsResource } from "./resources/reports";
import { DEFAULT_MAX_SOURCE_BYTES } from "./resources/source";
import { type Telemetry, Transport } from "./resources/transport";
import { WebhooksResource } from "./resources/webhooks";
import type {
	Entity,
	FileDeleteReceipt,
	Job,
	ListEntitiesResponse,
	ListFilesResponse,
	MatchingAnalysisCreateJobRequest,
	MatchingAnalysisJobReceipt,
	MatchingAnalysisResponse,
	MediaFile,
	MediaObject,
	MediaUploadRequest,
	RetentionLockResult,
} from "./types";

type ConduitClientOptions = {
	/** API key used for Conduit authenticated requests. */
	apiKey: string;
	/** Base API URL. Defaults to https://api.mappa.ai. */
	baseUrl?: string;
	/** Per-request timeout in milliseconds. Defaults to 300000. */
	timeoutMs?: number;
	/** Number of retry attempts for retryable requests. Defaults to 2. */
	maxRetries?: number;
	/** Headers included on every request. */
	defaultHeaders?: Record<string, string>;
	/** Custom fetch implementation. */
	fetch?: typeof fetch;
	/** User-Agent header value sent on requests. */
	userAgent?: string;
	/** Request/response/error instrumentation hooks. */
	telemetry?: Telemetry;
	/** Maximum source size accepted for file/url/path uploads. Defaults to 5GB. */
	maxSourceBytes?: number;
	/**
	 * Allow use from browser-like runtimes.
	 *
	 * This is unsafe for secret API keys and should only be used when
	 * credentials are intentionally exposed.
	 */
	dangerouslyAllowBrowser?: boolean;
};

type ConduitPrimitives = {
	entities: {
		get: (
			entityId: string,
			opts?: { requestId?: string; signal?: AbortSignal },
		) => Promise<Entity>;
		list: (opts?: {
			limit?: number;
			cursor?: string;
			requestId?: string;
			signal?: AbortSignal;
		}) => Promise<ListEntitiesResponse>;
		update: (
			entityId: string,
			body: { label?: string | null },
			opts?: { requestId?: string; signal?: AbortSignal },
		) => Promise<Entity>;
	};
	media: {
		upload: (req: MediaUploadRequest) => Promise<MediaObject>;
		get: (
			mediaId: string,
			opts?: { requestId?: string; signal?: AbortSignal },
		) => Promise<MediaFile>;
		list: (opts?: {
			limit?: number;
			cursor?: string;
			includeDeleted?: boolean;
			requestId?: string;
			signal?: AbortSignal;
		}) => Promise<ListFilesResponse>;
		delete: (
			mediaId: string,
			opts?: {
				idempotencyKey?: string;
				requestId?: string;
				signal?: AbortSignal;
			},
		) => Promise<FileDeleteReceipt>;
		setRetentionLock: (
			mediaId: string,
			locked: boolean,
			opts?: { requestId?: string; signal?: AbortSignal },
		) => Promise<RetentionLockResult>;
	};
	jobs: {
		get: (
			jobId: string,
			opts?: { requestId?: string; signal?: AbortSignal },
		) => Promise<Job>;
		cancel: (
			jobId: string,
			opts?: {
				idempotencyKey?: string;
				requestId?: string;
				signal?: AbortSignal;
			},
		) => Promise<Job>;
	};
};

class Conduit {
	public readonly matching: {
		create: (
			req: MatchingAnalysisCreateJobRequest,
		) => Promise<MatchingAnalysisJobReceipt>;
		get: (
			matchingId: string,
			opts?: { requestId?: string; signal?: AbortSignal },
		) => Promise<MatchingAnalysisResponse>;
	};
	public readonly reports: ReportsResource;
	public readonly primitives: ConduitPrimitives;
	public readonly webhooks: WebhooksResource;

	/** Create a new client instance. */
	constructor(options: ConduitClientOptions) {
		if (!options.apiKey) {
			throw new InitializationError("apiKey is required", {
				code: "config_error",
			});
		}
		if (isBrowserRuntime() && !options.dangerouslyAllowBrowser) {
			throw new InitializationError(
				"Conduit SDK cannot run in browser environments by default because API keys are secret. Use a server/edge proxy or pass dangerouslyAllowBrowser: true only if you understand the risk.",
				{ code: "unsupported_runtime" },
			);
		}

		const baseUrl = options.baseUrl ?? "https://api.mappa.ai";
		if (!isValidUrl(baseUrl)) {
			throw new InitializationError("baseUrl must be a valid URL", {
				code: "config_error",
			});
		}
		const timeoutMs = options.timeoutMs ?? 300000;
		const maxRetries = options.maxRetries ?? 2;
		const maxSourceBytes = options.maxSourceBytes ?? DEFAULT_MAX_SOURCE_BYTES;

		const transport = new Transport({
			apiKey: options.apiKey,
			baseUrl,
			defaultHeaders: options.defaultHeaders,
			fetch: options.fetch,
			maxRetries,
			telemetry: options.telemetry,
			timeoutMs,
			userAgent: options.userAgent,
		});

		const files = new FilesResource(transport, {
			fetchImpl: options.fetch,
			maxSourceBytes,
			timeoutMs,
		});
		const jobs = new JobsResource(transport);
		const entities = new EntitiesResource(transport);
		const matching = new MatchingAnalysisResource(transport, jobs);
		this.matching = {
			create: matching.create.bind(matching),
			get: matching.get.bind(matching),
		};
		this.reports = new ReportsResource(transport, jobs, files);
		this.primitives = {
			entities: {
				get: entities.get.bind(entities),
				list: entities.list.bind(entities),
				update: entities.update.bind(entities),
			},
			jobs: {
				cancel: jobs.cancel.bind(jobs),
				get: jobs.get.bind(jobs),
			},
			media: {
				delete: files.delete.bind(files),
				get: files.get.bind(files),
				list: files.list.bind(files),
				setRetentionLock: files.setRetentionLock.bind(files),
				upload: files.upload.bind(files),
			},
		};
		this.webhooks = new WebhooksResource();
	}
}

function isBrowserRuntime(): boolean {
	if (typeof globalThis.window === "undefined") return false;
	if (typeof document === "undefined") return false;
	return true;
}

function isValidUrl(value: string): boolean {
	try {
		new URL(value);
		return true;
	} catch {
		return false;
	}
}

export type { ConduitClientOptions, ConduitPrimitives };
export { Conduit };
