import { RequestAbortedError, TimeoutError } from "../errors";

export function getHeader(headers: Headers, name: string): string | undefined {
	const value = headers.get(name);
	if (value === null) return;
	return value;
}

export function jitter(ms: number): number {
	const ratio = 0.8 + Math.random() * 0.4;
	return Math.floor(ms * ratio);
}

export function backoffMs(
	attempt: number,
	baseMs: number,
	maxMs: number,
): number {
	const ms = baseMs * 2 ** Math.max(0, attempt - 1);
	if (ms > maxMs) return maxMs;
	return ms;
}

export function hasAbortSignal(signal?: AbortSignal): boolean {
	return !!signal && typeof signal.aborted === "boolean";
}

export function withDeadline(
	timeoutMs: number,
	opts?: {
		signal?: AbortSignal;
		onTimeout?: () => Error;
		onAbort?: () => Error;
	},
): { signal: AbortSignal; cleanup: () => void } {
	const ctrl = new AbortController();
	const timeout = setTimeout(() => {
		ctrl.abort(
			opts?.onTimeout?.() ??
				new TimeoutError(`The operation timed out after ${timeoutMs}ms`, {
					code: "timeout",
				}),
		);
	}, timeoutMs);

	if (opts?.signal?.aborted) {
		clearTimeout(timeout);
		throw (
			(opts.signal.reason instanceof Error ? opts.signal.reason : undefined) ??
			opts.onAbort?.() ??
			new RequestAbortedError("The operation was aborted", {
				code: "request_aborted",
			})
		);
	}

	opts?.signal?.addEventListener(
		"abort",
		() =>
			ctrl.abort(
				(opts.signal?.reason instanceof Error
					? opts.signal.reason
					: undefined) ??
					opts.onAbort?.() ??
					new RequestAbortedError("The operation was aborted", {
						code: "request_aborted",
					}),
			),
		{ once: true },
	);

	return {
		cleanup: () => clearTimeout(timeout),
		signal: ctrl.signal,
	};
}

export function randomId(prefix = "req"): string {
	if (
		typeof crypto !== "undefined" &&
		typeof crypto.randomUUID === "function"
	) {
		return `${prefix}_${crypto.randomUUID().replace(/-/g, "")}`;
	}
	return `${prefix}_${Math.random().toString(16).slice(2)}${Date.now().toString(16)}`;
}
